const raw=$('Obter código atual do convite').first().json;
const cfg=$('Configurar grupo').first().json;
let code='';
if (typeof raw==='string') code=raw;
else code=String(raw.inviteCode ?? raw.invite_code ?? raw.code ?? raw.value ?? raw.result ?? '').trim();
code=code.replace(/^https?:\/\/chat\.whatsapp\.com\//i,'').trim();
if (!code) throw new Error('O WAHA não retornou o código atual do convite do grupo.');
const link=`https://chat.whatsapp.com/${code}`;
return items.map((item)=>{
 const c=item.json; const first=String(c.nome||'').trim().split(/\s+/)[0];
 const hi=first?`Olá, ${first}.`:'Olá.';
 const text=[
  hi,
  'Neste momento, sua candidatura não avançou para esta vaga específica.',
  '',
  'Como novas oportunidades são divulgadas com frequência, você pode entrar em nosso grupo de vagas pelo link abaixo:',
  link,
  '',
  'Quando encontrar uma vaga compatível, é só nos chamar novamente no privado. Você continuará podendo participar de novos processos.'
 ].join('\n');
 return {json:{...c,session:cfg.sessao_waha,chatId:String(c.telefone||'').replace(/\D/g,'')+'@c.us',grupo_id:cfg.grupo_id,codigo_convite:code,link_convite:link,text}};
});

