WITH g AS (
  INSERT INTO grupo_convites_envios (
    candidato_id, grupo_id, codigo_convite, link_convite, mensagem, status, mensagem_waha_id, enviado_em, created_at, updated_at
  ) VALUES ($1,$2,$3,$4,$5,'ENVIADO',NULLIF($6::TEXT,''),NOW(),NOW(),NOW())
  ON CONFLICT (candidato_id, grupo_id)
  DO UPDATE SET codigo_convite=EXCLUDED.codigo_convite, link_convite=EXCLUDED.link_convite, mensagem=EXCLUDED.mensagem,
    status='ENVIADO', mensagem_waha_id=EXCLUDED.mensagem_waha_id, enviado_em=NOW(), updated_at=NOW()
  RETURNING id
), m AS (
  INSERT INTO mensagens (candidato_id, quem, mensagem, created_at) VALUES ($1,'IA',$5,NOW()) RETURNING id
), e AS (
  INSERT INTO eventos (candidato_id, evento, descricao, created_at) VALUES ($1,'CONVITE_GRUPO_VAGAS_ENVIADO',$4,NOW()) RETURNING id
)
SELECT id FROM g;
